select 
from exam
where deleted = 0

    and exam_name like concat('%', #{query.examName}, '%')


    and status = #{query.status}


    and creator_id = #{creatorId}

order by id desc
limit #{offset}, #{query.pageSize}

select count(1)
from exam
where deleted = 0

    and exam_name like concat('%', #{query.examName}, '%')


    and status = #{query.status}


    and creator_id = #{creatorId}

select e.id, e.exam_name, e.paper_id, e.subject_id, e.creator_id, e.start_time, e.end_time, e.duration_minutes, e.pass_score, e.max_switch_count, e.status, e.result_published, e.create_time, e.update_time, e.deleted from exam e inner join exam_student es on e.id = es.exam_id and es.deleted = 0 where e.deleted = 0 and es.student_id = #{studentId} and e.status != 'DRAFT'
and e.status in ('ENDED', 'GRADED', 'RESULT_PUBLISHED')
and e.status = #{status}
order by e.id desc limit #{offset}, #{pageSize}

select count(1) from exam e inner join exam_student es on e.id = es.exam_id and es.deleted = 0 where e.deleted = 0 and es.student_id = #{studentId} and e.status != 'DRAFT'
and e.status in ('ENDED', 'GRADED', 'RESULT_PUBLISHED')
and e.status = #{status}
